import{_ as o,o as t,c as i,a2 as a}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"F09: 毛利變動與經營槓桿審計","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F09_毛利變動與經營槓桿審計_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F09_毛利變動與經營槓桿審計_財務分析專家.md"}'),l={name:"32Ｑ題本＿重要/財務組/F09_毛利變動與經營槓桿審計_財務分析專家.md"};function r(e,n,s,g,c,_){return t(),i("div",null,[...n[0]||(n[0]=[a('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f09-毛利變動與經營槓桿審計" tabindex="-1">F09: 毛利變動與經營槓桿審計 <a class="header-anchor" href="#f09-毛利變動與經營槓桿審計" aria-label="Permalink to &quot;F09: 毛利變動與經營槓桿審計&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F09</li><li><strong>題目：</strong> 毛利率 (GM)、營業利益率 (OPM) 與淨利率的連動關係為何？是否存在經營槓桿 (Operating Leverage) 放大或侵蝕損益的現象？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「獲利結構拆解 (Profit Structure Breakdown)」與「成本習性分析」。具備透過三率連動判定公司是否具備「規模經濟」或陷入「低效擴張」的能力。其核心價值在於識別企業獲利的「含金量」與「防禦邊界」。</li><li><strong>意圖：</strong> 執行「獲利能力與經營槓桿審計」。透過分析三率（毛利、營業利益、淨利）的趨勢，判定公司是否具備「定價權」與「成本控管能力」。識別在營收成長時，利潤是否能以更大幅度跳升（正向槓桿），或在營收衰退時，利潤是否因固定成本過高而劇烈萎縮（負向槓桿）。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 提取「營業收入」、「營業成本」、「營業費用」、「營業利益」以及「稅後淨利」。</li><li><strong>【深度事實溯源：Annual Report (年報)】</strong>：查閱「五年財務摘要」與「管理層討論與分析 (MD&amp;A)」。</li><li><strong>【穿透校準：法說會簡報】</strong>：檢索關於「成本控制計劃」或「產品組合優化 (Mix improvement)」之官方指引。</li></ol></li><li><strong>邏輯：</strong> 執行「三率連動算則」——分析毛利率上升是否被營費率（行銷支出）沖銷；執行「經營槓桿效率檢驗」——分析營收成長 1% 能帶動營業利益成長多少個基點 (bps)。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py margin_analysis [股號]</code> → 取得 GM/OPM/NPM、經營槓桿</li><li><strong>判讀三率</strong>：三率同升 = 規模經濟；毛利率升但營益率降 = 費用失控；三率同降 = 競爭力衰退</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具提取「產品別毛利率」明細</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①空頭視角 ≥2 個關鍵字；②專家評析 ≥200 字；③量化趨勢而非文字描述</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【三率趨勢事實優先】</strong>：智慧體<strong>必須</strong>列出近八個季度的毛利率 (GM) 與營業利益率 (OPM) 趨勢。嚴禁進行模糊的「控管表現良好」之結論。</li><li><strong>【費用侵蝕臨界審查】</strong>：若毛利率上升但營益率下滑，智慧體必須強制識別企業是否為維持營收而陷入「燒錢行銷」陷阱。標註為「低效擴張風險」。</li><li><strong>【定價權與成本彈性】</strong>：對比同業平均。若本企毛利高於同業 5% 以上且能轉嫁原料成本，判定具備「結構性定價保護」。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述指標】</strong>：絕對禁用「獲利優異」、「控管不一」。必須量化為具體的「營益率變動 bps」與「費用率（OpEx Ratio）」趨勢。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f09-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F09 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f09-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F09 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「三率連動+定性判定」結構（例：三率同升顯示強大 [規模經濟/產品溢價]；或毛利升但營益降，判定 [經營槓桿惡化/競爭加劇]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：三率同步上升或維持高位，顯示強大的品牌定價權與極佳的營運效率，經營槓桿正處於高效收割期。</li><li><strong>A (良)</strong>：獲利結構穩定，費用增幅受控於營收增幅內，資產利用效率維持在產業前端。</li><li><strong>B (持平)</strong>：毛利率連續下滑或營益率因費用失控而萎縮，顯示公司正面臨「低價搶單」或「管理效能遞減」之風險。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 FinMind <code>financial</code> 損益表與年報 P.XXX 五年財務摘要表。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注研發費用 (R&amp;D) 的動態。若毛利率下滑但研發穩定投入，專家應在此處診斷為「轉型期的技術築牆」；若推銷費用暴增而營收增幅低於 5%，則應診斷為「產品競爭力衰竭之訊號」。判定這是「技術開道」還是「補貼換盤」。</li></ul>',12)])])}const h=o(l,[["render",r]]);export{f as __pageData,h as default};
